def search_range(nums, target):
    def find_first(nums, target):
        lo, hi = 0, len(nums) - 1
        while lo < hi:
            mid = (lo + hi) // 2
            if nums[mid] >= target:
                hi = mid
            else:
                lo = mid + 1
        return lo if lo < len(nums) and nums[lo] == target else -1

    def find_last(nums, target):
        lo, hi = 0, len(nums) - 1
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if nums[mid] <= target:
                lo = mid
            else:
                hi = mid - 1
        return lo if lo < len(nums) and nums[lo] == target else -1

    if not nums:
        return [-1, -1]

    start = find_first(nums, target)
    if start == -1:
        return [-1, -1]
    end = find_last(nums, target)
    return [start, end]

